import anthropic

client = anthropic.Anthropic()

# Standard response — model reasons implicitly while generating tokens.
# Reasoning is not exposed in the response; only the output is returned.
response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=4096,
    messages=[{
        "role": "user",
        "content": "Identify the three most likely causes of this 500 error and suggest a fix for each.",
    }],
)

for block in response.content:
    if hasattr(block, "text"):
        print(block.text)

import anthropic

client = anthropic.Anthropic()

# Extended thinking — model has an explicit reasoning budget before answering.
# thinking blocks appear in response.content before text/tool_use blocks.
response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=16000,        # must be > budget_tokens
    thinking={
        "type": "enabled",
        "budget_tokens": 8000,   # tokens the model may spend on reasoning
    },
    messages=[{
        "role": "user",
        "content": "Design the database schema for a multi-tenant SaaS application with row-level security.",
    }],
)

for block in response.content:
    if block.type == "thinking":
        # Reasoning trace — useful for debugging; do not include in messages
        # that continue the loop (the model already knows what it thought).
        print(f"[thinking: {len(block.thinking)} chars]")
    elif block.type == "text":
        print(block.text)
    elif block.type == "tool_use":
        print(f"[tool_use: {block.name}]")

import anthropic
from typing import Literal


client = anthropic.Anthropic()

TaskDifficulty = Literal["standard", "hard"]


def classify_difficulty(task: str) -> TaskDifficulty:
    hard_signals = [
        "design", "architecture", "trade-off", "proof",
        "security", "optimise", "compare approaches",
    ]
    if any(s in task.lower() for s in hard_signals):
        return "hard"
    return "standard"


def agent_step(
    messages: list[dict],
    tools: list[dict],
    difficulty: TaskDifficulty = "standard",
) -> anthropic.types.Message:
    """
    Run one agent loop step, optionally with extended thinking for hard tasks.
    """
    kwargs: dict = {
        "model": "claude-sonnet-4-6",
        "tools": tools,
        "messages": messages,
    }

    if difficulty == "hard":
        # Extended thinking: budget + sufficient max_tokens headroom
        kwargs["thinking"] = {"type": "enabled", "budget_tokens": 8000}
        kwargs["max_tokens"] = 16000
    else:
        kwargs["max_tokens"] = 4096

    return client.messages.create(**kwargs)


def extract_text_blocks(response: anthropic.types.Message) -> list[str]:
    """Return only text block content, skipping thinking and tool_use blocks."""
    return [
        block.text
        for block in response.content
        if block.type == "text"
    ]


def build_assistant_turn(response: anthropic.types.Message) -> dict:
    """
    Build the assistant turn for appending to the messages list.
    Thinking blocks MUST be included when continuing a conversation that
    used extended thinking — the API requires them for coherence.
    """
    return {"role": "assistant", "content": response.content}

import pytest


class TestExtractTextBlocks:
    def _make_response_content(self, types):
        """Build a fake content list with given block types."""
        blocks = []
        for t in types:
            if t == "thinking":
                blocks.append(type("B", (), {"type": "thinking", "thinking": "..."})())
            elif t == "text":
                blocks.append(type("B", (), {"type": "text", "text": "answer"})())
            elif t == "tool_use":
                blocks.append(type("B", (), {"type": "tool_use", "name": "read_file", "id": "1", "input": {}})())
        return blocks

    def test_returns_only_text(self):
        content = self._make_response_content(["thinking", "text", "tool_use"])
        mock_response = type("R", (), {"content": content})()
        texts = extract_text_blocks(mock_response)
        assert texts == ["answer"]

    def test_empty_when_no_text(self):
        content = self._make_response_content(["thinking", "tool_use"])
        mock_response = type("R", (), {"content": content})()
        assert extract_text_blocks(mock_response) == []


