import anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "read_file",
        "description": "Read a file from the local filesystem.",
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string"}},
            "required": ["path"],
        },
    }
]


def agent_loop_with_thinking(task: str) -> str:
    """
    Agent loop that uses extended thinking on the first planning step,
    then reverts to standard mode for subsequent execution steps.
    """
    messages = [{"role": "user", "content": task}]
    step = 0

    while True:
        # Use thinking only on the planning step
        use_thinking = step == 0

        kwargs = {
            "model": "claude-sonnet-4-6",
            "tools": tools,
            "messages": messages,
        }
        if use_thinking:
            kwargs["thinking"] = {"type": "enabled", "budget_tokens": 6000}
            kwargs["max_tokens"] = 12000
        else:
            kwargs["max_tokens"] = 4096

        response = client.messages.create(**kwargs)
        # IMPORTANT: include response.content as-is; thinking blocks must be preserved
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if block.type == "text":
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": open(block.input["path"]).read() if block.name == "read_file" else "ok",
                })
        messages.append({"role": "user", "content": tool_results})
        step += 1
